Map yaratmaq üçün `<map>` başlıq faylı daxil edilir və aşağıdakı sintaksisdən istifadə olunur:
#include <map>
std::map<key_type, value_type> map_name;
Məsələn, `std::map<std::string, int> students;` tələbə adlarını və qiymətlərini saxlayan bir map yaradır.

content.code:
#include <iostream>
#include <map>
#include <string>

int main() {
  std::map<std::string, int> students;
  students["Ali"] = 85;
  students["Veli"] = 90;
  students["Ayşe"] = 95;
  for(const auto& pair : students) {
    std::cout << pair.first << ": " << pair.second << std::endl;
  }
  return 0;
}
// Output:
// Ali: 85
// Ayşe: 95
// Veli: 90

#include <iostream>
#include <map>
#include <string>

int main() {
  std::map<std::string, int> students;
  students.insert({"Ali", 85});
  students.insert({"Veli", 90});
  auto it = students.find("Ali");
  if(it != students.end()) {
    std::cout << "Found: " << it->first << ": " << it->second << std::endl;
  }
  students.erase("Veli");
  std::cout << "Size: " << students.size() << std::endl;
  return 0;
}
// Output:
// Found: Ali: 85
// Size: 1

